function getRandomColor() {
  var letters = '0123456789ABCDEF';
  var color = '#';
  for (var i = 0; i < 6; i++) {
    color += letters[Math.floor(Math.random() * 16)];
  }
  return color;
}

const MultipleTargetTable = ({
  data,
  comments,
  updateCommentValue,
  sendComment,
}) => {
  return (
    <div>
      {Object.entries(data)
        .sort(([k1, v1], [k2, v2]) => k2 - k1)
        .map(([k, v]) => (
          <div className="breakinside" key={k}>
            <div className="print-only">
              <div className="flex justify-center">
                <Header />
              </div>
              <div className="mt-5">
                <div className="inline-block">Delegue</div>{" "}
                <div className="inline-block bg-green-500 p-1 rounded-md font-bold">
                  {v.user}
                </div>
              </div>
              <div className="flex gap-3 mt-5 items-center flex-wrap">
                Wilayas
                {v.wilayas.map((e) => (
                  <div className="bg-green-500 p-1 rounded-md font-bold text-[9px]">
                    <span>{e}</span>
                  </div>
                ))}
              </div>

              <div className="flex gap-3 mt-5 items-center">
                Mois
                {v.months.map((e) => (
                  <div className="bg-green-500 p-1 rounded-md font-bold">
                    <span>{get_month_name(e)}</span>
                  </div>
                ))}
                - <div className="font-bold">{v.years[0]}</div>
              </div>
            </div>
            <div className="my-5 font-bold bg-green-500 p-1 rounded-md text-center">
              Tableau de Vente du Mois de {get_month_name(k)}
            </div>

            <TargetTable data={v} />

            <div className="">Commentaires</div>

            <div className="">
              {v.comments.map((e) => (
                <CommentSection key={e.id} data={e} />
              ))}
            </div>

            <Comment
              identity={v.months[0]}
              value={comments.id == v.months[0] ? comments.value : ""}
              loading={comments.loading}
              on_change={updateCommentValue}
              on_send={() => sendComment(v.years[0], v.months[0])}
            />
          </div>
        ))}
    </div>
  );
};

export default function Home() {
  const [_is_loading, set_is_loading] = useState(false);

  const [_user_data, set_user_data] = useState();
  const [_users, setUsers] = useState({ options: [], selectedValues: [] });
  const [_months, setMonths] = useState({ options: [], selectedValues: [] });
  const [_years, setYears] = useState({ options: [], selectedValues: [] });
  const [_comment, setComment] = useState({
    id: -1,
    value: "",
    loading: false,
  });

  const post_month_comment = (year, month) => {
    console.log(_users.selectedValues[0]);
    setComment({ ...comment, loading: true });
    axios({
      method: "post",
      url: "MONTH_COMMENT",
      data: {
        year: year,
        month: month,
        to_user: _users.selectedValues.length === 1 ? _users.selectedValues[0].key : _user_data.user.id,
        comment: _comment.value,
      },
    })
      .then((res) => {
        fetch_user_data();
        setComment({ id: -1, value: "", loading: false });
      })
      .catch((err) => {
        console.log("Failed to Comment");
        console.log(err);
      });
  };

  const updateCommentValue = (key, value) => {
    setComment({ id: key, value: value });
  };


  useEffect(() => {
    fetch_user_data();
    return () => { };
  }, []);

  const axios = require("axios");

  const fetch_user_data = () => {
    set_is_loading(true);
    axios({
      method: "get",
      url: "USERS_DATA",
      params: {
        users: _users.selectedValues.map((e) => e.key),
        months: _months.selectedValues.map((e) => e.key),
        years: _years.selectedValues.map((e) => e.key),
      },
    })
      .then((res) => {
        set_is_loading(false);
        set_user_data(res.data);

        console.log(res);

        setUsers({
          ..._users,
          options: res.data.users.map((e) => ({
            key: e.id,
            label: e.username,
          })),
        });
        setMonths({
          ..._months,
          options: res.data.all_months.map((e) => ({
            key: e,
            label: `${e} - ${get_month_name(e)}`,
          })),
        });
        setYears({
          ..._years,
          options: res.data.all_years.map((e) => ({ key: e, label: e })),
        });
      })
      .catch((err) => {
        set_is_loading(false);
      });
  };

  /**
   * 
   *  Total Target > 100%
   *  Achieved > ?
   * 
   * 
   * 
   */

  const chartData = useMemo(() =>
  (
    _user_data && _user_data.data ?
      _user_data.data.products.map((value, index) => ({ title: `${value} ${((parseFloat(_user_data.data.total_achievements[index].replaceAll(",", "")) / parseFloat(_user_data.data.total_targets[index].replaceAll(",", ""))) * 100).toFixed(2)}%`, value: _user_data.data.quantities[index].total, color: getRandomColor() }))
      : []
  )
    , [_is_loading])

  console.log(chartData);

  return (
    <>

      <div className="no-print">
        <Header />
      </div>
      <div className="p-5 px-4 flex items-center">
        <div className="grow">
          <div className="flex items-center ">


            {_user_data !== undefined && (
              <div className="flex gap-3 flex-wrap justify-end no-print">
                {_user_data.users.length > 0 && (
                  <div className="flex-1">
                    Users
                    <MultiselectDropDown
                      state={_users}
                      setState={setUsers}
                      keyName="label"
                      placeholder="Choisissez le Délégué"
                      selectionLimit={1}
                    />
                  </div>
                )}

                <div className="flex-1">
                  Months
                  <MultiselectDropDown
                    state={_months}
                    setState={setMonths}
                    keyName="label"
                    placeholder="Choisissez le Mois"
                  />
                </div>

                <div className='flex-1'>
                  Years
                  <MultiselectDropDown
                    state={_years}
                    setState={setYears}
                    keyName="label"
                    placeholder="Choisissez l'année"
                  />
                </div>

                <div className="flex flex-1 gap-3">

                  <button
                    className={
                      "bg-green-600 p-2 flex-1 rounded-md self-end " +
                      (_is_loading && "opacity-50")
                    }
                    onClick={() => !_is_loading && fetch_user_data()}
                  >
                    Rechercher
                  </button>

                  <button
                    className={
                      "bg-green-600 p-2 rounded-md self-end hide_on_mobile " +
                      (_is_loading && "opacity-50")
                    }
                    onClick={window.print}
                    target="_blank"
                  >
                    <FeatherIcon icon="printer" />
                  </button>
                </div>

                {_is_loading && (
                  <div className="self-center">
                    <Loader />
                  </div>
                )}
              </div>
            )}
          </div>

          {_user_data && (
            <div>


              <div className="flex gap-3 mt-5 items-center">
                Mois
                {_months.selectedValues.length == 0 ?
                  <div className="bg-green-500 p-1 rounded-md font-bold">Tout les Mois de {_user_data.all_years[0]}</div>
                  :
                  <div className="flex gap-3 items-center">
                    {_months.selectedValues.map((e) => (
                      <div className="bg-green-500 p-1 rounded-md font-bold">
                        <span>{e.label}</span>
                      </div>
                    ))}
                    <div className="font-bold">{_user_data.all_years[0]}</div>
                  </div>
                }
              </div>


              {_months.selectedValues.length == 1 ? (
                <div>
                  <MultipleTargetTable
                    data={_user_data.data.other_months}
                    comments={_comment}
                    updateCommentValue={updateCommentValue}
                    sendComment={post_month_comment}
                  />
                </div>
              ) : (
                <div>
                  <div className="print-only">
                    <div className="flex justify-center">
                      <Header />
                    </div>
                  </div>
                  <div className="mt-5">
                    <div className="inline-block">Delegue</div>{" "}
                    <div className="inline-block bg-green-500 p-1 rounded-md font-bold">
                      {_user_data.data.user}
                    </div>
                  </div>

                  <div className="flex gap-3 mt-5 items-center max-w-full flex-wrap">
                    Wilayas
                    {_user_data.data.wilayas.map((e) => (
                      <div className="bg-green-500 p-1 rounded-md font-bold text-[9px]">
                        <span>{e}</span>
                      </div>
                    ))}
                  </div>


                  <div className="text-center text-xl font-bold my-5 bg-red-500 p-1 rounded-md">
                    Total des Ventes Mensuel
                  </div>
                  <TargetTable
                    data={_user_data.data}
                    months={_months.selectedValues}
                    comments={_comment}
                    updateCommentValue={updateCommentValue}
                    sendComment={post_month_comment}
                  />

                  <MultipleTargetTable
                    data={_user_data.data.other_months}
                    comments={_comment}
                    updateCommentValue={updateCommentValue}
                    sendComment={post_month_comment}
                  />
                </div>
              )}
            </div>
          )}
        </div>

        
      </div>

      <div className="flex items-center gap-5">
              <PieChart
                className="max-w-sm"
                label={(props) => props.dataEntry.title}
                data={chartData}
                labelStyle={{
                  fill: 'white',
                  fontSize: '2px'
                }} />

              <div className="flex flex-col gap-3 text-xs">
                {
                  chartData.map((d) =>
                    <div className="w-fit flex gap-3">
                      <div className="w-5 h-5"style={{ backgroundColor: d.color }}></div>
                      <div><p>{d.title}</p></div>
                    </div>
                  )
                }
              </div>

            </div>

    </>
  );
}
