import React from 'react'
import { default as MultiSelectDropDown } from 'multiselect-react-dropdown';

/*
DOCS

State Should be Declared as Follow:
const [state, setState] = useState({ options: [], selectedValues: [] });

Example of Component Use:
<MultiselectDropDown
    state={_months}
    setState={setMonths}
    keyName="key"
    placeholder="Select"
/>

*/

const Multiselect = ({ state, setState, keyName, placeholder, selectionLimit, singleSelect = false }) => {

    const onSelect = (selectedList, selectedItem) => {
        setState({ ...state, selectedValues: selectedList })
    }

    const onRemove = (selectedList, removedItem) => {
        setState({ ...state, selectedValues: selectedList })
    }

    return (
        <MultiSelectDropDown
            options={state.options}
            selectedValues={state.selectedValues}
            onSelect={onSelect}
            onRemove={onRemove}
            displayValue={keyName}
            singleSelect={singleSelect}
            placeholder={placeholder}
            selectionLimit={selectionLimit}
            style={{
                optionContainer: {
                    backgroundColor: "black"
                }
            }}
        />
    )
}

export default Multiselect